class ClassName {
private:
    const int m_id;
    int* m_data;
public:
    // 1. Default Constructor
    ClassName() : m_id(0), m_data(nullptr) {}

    // 2. Parameterized Constructor with Member Initialization List
    ClassName(int id, int value) : m_id(id), m_data(new int(value)) {}

    // 3. Constructor Delegation
    ClassName(int id) : ClassName(id, -1) {}

    // 4. Copy Constructor (Deep Copy)
    ClassName(const ClassName& other) : m_id(other.m_id), m_data(other.m_data ? new int(*other.m_data) : nullptr) {}

    // 5. Destructor
    ~ClassName() {
        delete m_data;
    }
};

