#include <iostream>
#include <string>

class Tracker {
private:
    std::string m_label;
public:
    // Default Constructor
    Tracker() : m_label("Default") {
        std::cout << "[Default Constructor] Created: " << m_label << "\n";
    }

    // Parameterized Constructor
    Tracker(std::string label) : m_label(std::move(label)) {
        std::cout << "[Parameterized Constructor] Created: " << m_label << "\n";
    }

    // Copy Constructor
    Tracker(const Tracker& other) : m_label(other.m_label + " (Copy)") {
        std::cout << "[Copy Constructor] Cloned: " << m_label << "\n";
    }

    // Destructor
    ~Tracker() {
        std::cout << "[Destructor] Destroyed: " << m_label << "\n";
    }
};

int main() {
    std::cout << "-- Scope Entry --\n";
    Tracker t1;
    Tracker t2("Custom");
    Tracker t3 = t2; // Calls Copy Constructor
    std::cout << "-- Scope Exit Looming --\n";
    return 0;
}

