#include <iostream>
#include <algorithm>

class DynamicBuffer {
private:
    size_t m_size;
    int* m_data;
public:
    // Default Constructor
    DynamicBuffer() : m_size(0), m_data(nullptr) {
        std::cout << "Constructed empty buffer.\n";
    }

    // Parameterized Constructor (Acquires heap memory)
    DynamicBuffer(size_t size) : m_size(size), m_data(size > 0 ? new int[size]{} : nullptr) {
        std::cout << "Constructed buffer of size " << m_size << ".\n";
    }

    // Copy Constructor (Deep Copy logic to prevent memory sharing)
    DynamicBuffer(const DynamicBuffer& other) : m_size(other.m_size), m_data(other.m_size > 0 ? new int[other.m_size] : nullptr) {
        if (m_data) {
            std::copy(other.m_data, other.m_data + m_size, m_data);
        }
        std::cout << "Deep-copied buffer of size " << m_size << ".\n";
    }

    // Destructor (Ensures dynamic memory is cleaned up correctly)
    ~DynamicBuffer() {
        delete[] m_data;
        std::cout << "Destroyed buffer of size " << m_size << " and freed allocated memory.\n";
    }

    void setValue(size_t index, int value) {
        if (index < m_size) {
            m_data[index] = value;
        }
    }

    void print() const {
        std::cout << "Buffer contents: ";
        for (size_t i = 0; i < m_size; ++i) {
            std::cout << m_data[i] << " ";
        }
        std::cout << "\n";
    }
};

int main() {
    std::cout << "Creating original buffer...\n";
    DynamicBuffer original(3);
    original.setValue(0, 10);
    original.setValue(1, 20);
    original.setValue(2, 30);

    std::cout << "Creating copy of buffer...\n";
    DynamicBuffer clone = original; // Triggers Deep Copy

    std::cout << "Modifying copy...\n";
    clone.setValue(0, 99);

    std::cout << "Original ";
    original.print();
    std::cout << "Copy ";
    clone.print();

    std::cout << "Exiting application main...\n";
    return 0;
}

