#include <fstream>
#include <string>

class FileHandler {
private:
    std::ofstream m_file;
public:
    FileHandler(const std::string& filename) : m_file(filename) {}

    ~FileHandler() {
        if (m_file.is_open()) {
            m_file.close();
        }
    }

    // Prevent copying
    FileHandler(const FileHandler&) = delete;
    FileHandler& operator=(const FileHandler&) = delete;

    void write(const std::string& text) {
        if (m_file.is_open()) {
            m_file << text;
        }
    }
};

class Point3D {
private:
    float m_x, m_y, m_z;
public:
    // Target Parameterized Constructor
    Point3D(float x, float y, float z) : m_x(x), m_y(y), m_z(z) {}

    // 2-Parameter Delegating Constructor
    Point3D(float x, float y) : Point3D(x, y, 0.0f) {}

    // Default Delegating Constructor
    Point3D() : Point3D(0.0f, 0.0f, 0.0f) {}
};

