#include <cstring>
#include <algorithm>

class SimpleString {
private:
    char* m_str;
public:
    SimpleString() : m_str(nullptr) {
        m_str = new char[1];
        m_str[0] = '\0';
    }

    SimpleString(const char* s) {
        if (s) {
            m_str = new char[std::strlen(s) + 1];
            std::strcpy(m_str, s);
        } else {
            m_str = new char[1];
            m_str[0] = '\0';
        }
    }

    // Deep Copy Constructor
    SimpleString(const SimpleString& other) {
        m_str = new char[std::strlen(other.m_str) + 1];
        std::strcpy(m_str, other.m_str);
    }

    ~SimpleString() {
        delete[] m_str;
    }

    const char* c_str() const { return m_str; }
};

#include <iostream>

class SharedResource {
private:
    int* m_value;
    int* m_refCount;
public:
    SharedResource(int val) : m_value(new int(val)), m_refCount(new int(1)) {}

    // Copy Constructor increments tracking counters
    SharedResource(const SharedResource& other) : m_value(other.m_value), m_refCount(other.m_refCount) {
        if (m_refCount) {
            (*m_refCount)++;
        }
    }

    ~SharedResource() {
        if (m_refCount) {
            (*m_refCount)--;
            if (*m_refCount == 0) {
                delete m_value;
                delete m_refCount;
                std::cout << "Resources freed permanently.\n";
            }
        }
    }

    int getValue() const { return *m_value; }
    int getRefCount() const { return *m_refCount; }
};

